<template>
    <v-card class="results-card" rounded="xl" elevation="6">
        <v-card-title class="results-title">Wyniki Koncowe</v-card-title>
        <v-card-text>
            <div v-for="(player, index) in ranking" :key="player.name" class="row">
                <div class="position">{{ index + 1 }}</div>
                <div class="name">{{ player.name }}</div>
                <div class="score">{{ player.goalsScored }} goli</div>
            </div>
        </v-card-text>
    </v-card>
</template>
<script>
export default {
    name: 'Results',
    props: {
        players: {
            type: Array,
            required: true
        },
        lastTeam: {
            type: Object,
            required: true
        }
    },
    computed: {
        ranking() {
            return [...this.players, this.lastTeam].sort((a, b) => b.goalsScored - a.goalsScored);
        }
    }
}
</script>
<style scoped>
.results-card {
    max-width: 620px;
    margin: 0 auto;
}

.results-title {
    font-family: 'Bebas Neue', cursive;
    letter-spacing: 0.05em;
    font-size: 1.8rem;
}

.row {
    display: grid;
    grid-template-columns: 44px 1fr auto;
    align-items: center;
    gap: 10px;
    margin-bottom: 8px;
    padding: 10px;
    border-radius: 12px;
    background: rgba(0, 0, 0, 0.04);
}

.position {
    font-weight: 700;
    font-size: 1.1rem;
}

.name {
    font-weight: 600;
}

.score {
    font-weight: 700;
}
</style>