<template>
    <div class="player-block">
        <v-card class="player-card" rounded="xl" elevation="6">
            <v-card-title class="d-flex justify-space-between align-center">
                <span>{{ player.name }}</span>
                <v-chip size="small" color="primary" variant="tonal">{{ player.teams.length }} teams</v-chip>
            </v-card-title>
            <v-divider />
            <v-card-text>
                <v-list density="compact" v-if="visibleTeams.length">
                    <v-list-item v-for="team in visibleTeams" :key="team.name" class="list-item">
                        <div class="team-row">
                            <flag :iso="team.icon" />
                            <span class="team-name">{{ team.name }}</span>
                            <v-rating
                                :model-value="team.rating"
                                half-increments
                                readonly
                                color="amber"
                                size="18"
                            />
                        </div>
                    </v-list-item>
                </v-list>
                <div v-else class="placeholder">Kliknij Next, aby odslonic pierwsza druzyne.</div>
            </v-card-text>
        </v-card>
        <v-btn
            :disabled="isRevealDisabled"
            color="primary"
            rounded="lg"
            @click="next"
            class="mt-2 action-btn"
        >
            {{ lastTeam ? 'Reveal Team' : 'Next Team' }}
        </v-btn>
    </div>
</template>
<script>
export default {
    props: {
        player: {
            type: Object,
            required: true,
        },
        onBeforeReveal: {
            type: Function,
            default: null
        },
        lastTeam: {
            type: Boolean,
            default: false
        }
    },
    data() {
        return {
            revealedCount: 0
        }
    },
    computed: {
        visibleTeams() {
            return this.player.teams.slice(0, this.revealedCount);
        },
        isRevealDisabled() {
            return this.revealedCount >= this.player.teams.length;
        }
    },
    methods: {
        async next() {
            if (this.isRevealDisabled) {
                return
            }

            const nextTeam = this.player.teams[this.revealedCount];

            if (this.onBeforeReveal && nextTeam) {
                await this.onBeforeReveal({
                    owner: this.player.name,
                    team: nextTeam
                });
            }

            this.revealedCount += 1;
        }
    },
    watch: {
        'player.teams': {
            handler() {
                this.revealedCount = 0;
            },
            deep: true
        }
    }
}
</script>
<style scoped>
.player-block {
    display: flex;
    flex-direction: column;
    align-items: center;
}

.player-card {
    width: 100%;
    max-width: 320px;
}

.team-row {
    display: grid;
    grid-template-columns: 18px 1fr auto;
    align-items: center;
    gap: 10px;
}

.team-name {
    font-weight: 600;
}

.placeholder {
    font-size: 0.92rem;
    opacity: 0.7;
}

.action-btn {
    width: 100%;
    max-width: 320px;
}
</style>