<template>
    <div class="home-wrapper">
        <section class="hero">
            <h1>Big dick cup</h1>
            <p>Losuj druzyny, tworz grupy, wpisuj wyniki i sprawdzaj ranking strzelcow.</p>
            <div class="hero-actions">
                <v-btn color="primary" size="x-large" rounded="xl" prepend-icon="mdi-dice-multiple" @click="roll">
                    Roll Teams
                </v-btn>
                <span class="stats-chip" v-if="allTeams.length">Wszystkie gole: {{ totalGoals }}</span>
            </div>
        </section>

        <section class="draft-section" v-if="allTeams.length">
            <h2>Wylosowane sklady</h2>
            <div class="players-grid">
                <Player
                    v-for="player in players"
                    :player="player"
                    :key="player.name"
                    :onBeforeReveal="showTeamRevealAnimation"
                />
                <Player
                    :player="lastTeam"
                    :key="lastTeam.name"
                    :lastTeam="true"
                    :onBeforeReveal="showTeamRevealAnimation"
                />
            </div>
        </section>

        <section class="groups-section" v-if="allTeams.length">
            <h2>Faza Grupowa</h2>
            <div class="group-grid">
                <Group :teams="allTeams" groupName="A" :addGoalsScored="setGoalsScored" />
                <Group :teams="allTeams" groupName="B" :addGoalsScored="setGoalsScored" />
                <Group :teams="allTeams" groupName="C" :addGoalsScored="setGoalsScored" />
                <Group :teams="allTeams" groupName="D" :addGoalsScored="setGoalsScored" />
            </div>
        </section>

        <section class="knockout-section" v-if="allTeams.length">
            <h2>Puchar</h2>
            <Knockout :teams="allTeams" :addGoalsScored="setGoalsScored" />
        </section>

        <section class="results-section" v-if="allTeams.length">
            <Results :players="players" :lastTeam="lastTeam" />
        </section>

        <transition name="reveal-fade">
            <div v-if="revealActive" class="reveal-overlay">
                <div class="reveal-glow reveal-glow-left" />
                <div class="reveal-glow reveal-glow-right" />

                <div class="reveal-content">
                    <div class="reveal-header">
                        <span class="reveal-kicker">Reveal</span>
                        <h2>Nowa Druzyna</h2>
                        <p>{{ revealCurrentOwner }}</p>
                    </div>

                    <transition name="card-pop" mode="out-in">
                        <article v-if="revealItem" :key="`${revealItem.owner}-${revealItem.team.name}`" class="reveal-card">
                            <div class="owner-chip">{{ revealItem.owner }}</div>
                            <div class="team-line">
                                <h3>
                                    {{ revealTypedName }}
                                    <span class="typing-caret" v-if="isTypingName">|</span>
                                </h3>
                                <transition name="flag-pop">
                                    <flag v-if="revealShowFlag" :iso="revealItem.team.icon" class="reveal-flag" />
                                </transition>
                            </div>
                            <div class="team-rating" v-if="revealShowFlag">
                                <v-rating
                                    :model-value="revealItem.team.rating"
                                    half-increments
                                    readonly
                                    color="amber"
                                    size="22"
                                />
                            </div>
                        </article>
                    </transition>

                    <div class="reveal-actions">
                        <v-btn
                            color="white"
                            variant="outlined"
                            rounded="xl"
                            prepend-icon="mdi-skip-forward"
                            @click="skipRevealAnimation"
                        >
                            Skip Animation
                        </v-btn>
                    </div>
                </div>
            </div>
        </transition>
    </div>
</template>
<script>
import Player from '@/components/Player.vue';
import Group from '@/components/Group.vue';
import Knockout from '@/components/Knockout.vue';
import Results from '@/components/Results.vue';

const TEAMS = [
    { name: 'Argentyna', legacyName: 'Argentina', rating: 5, icon: 'ar' },
    { name: 'Chorwacja', legacyName: 'Croatia', rating: 4, icon: 'hr' },
    { name: 'Czechy', legacyName: 'Czechia', rating: 4, icon: 'cz' },
    { name: 'Dania', legacyName: 'Denmark', rating: 4, icon: 'dk' },
    { name: 'Anglia', legacyName: 'England', rating: 5, icon: 'gb-eng' },
    { name: 'Finlandia', legacyName: 'Finland', rating: 3.5, icon: 'fi' },
    { name: 'Francja', legacyName: 'France', rating: 5, icon: 'fr' },
    { name: 'Niemcy', legacyName: 'Germany', rating: 5, icon: 'de' },
    { name: 'Ghana', legacyName: 'Ghana', rating: 4, icon: 'gh' },
    { name: 'Wegry', legacyName: 'Hungary', rating: 3.5, icon: 'hu' },
    { name: 'Islandia', legacyName: 'Iceland', rating: 3.5, icon: 'is' },
    { name: 'Irlandia', legacyName: 'Ireland', rating: 3.5, icon: 'ie' },
    { name: 'Wlochy', legacyName: 'Italy', rating: 4.5, icon: 'it' },
    { name: 'Meksyk', legacyName: 'Mexico', rating: 4, icon: 'mx' },
    { name: 'Maroko', legacyName: 'Morocco', rating: 4, icon: 'ma' },
    { name: 'Holandia', legacyName: 'Netherlands', rating: 5, icon: 'nl' },
    { name: 'Nowa Zelandia', legacyName: 'New Zealand', rating: 2.5, icon: 'nz' },
    { name: 'Irlandia Polnocna', legacyName: 'Northern Ireland', rating: 3, icon: 'gb-nir' },
    { name: 'Norwegia', legacyName: 'Norway', rating: 4, icon: 'no' },
    { name: 'Polska', legacyName: 'Poland', rating: 4, icon: 'pl' },
    { name: 'Portugalia', legacyName: 'Portugal', rating: 5, icon: 'pt' },
    { name: 'Katar', legacyName: 'Qatar', rating: 3, icon: 'qa' },
    { name: 'Rumunia', legacyName: 'Romania', rating: 3.5, icon: 'ro' },
    { name: 'Szkocja', legacyName: 'Scotland', rating: 4, icon: 'gb-sct' },
    { name: 'Hiszpania', legacyName: 'Spain', rating: 5, icon: 'es' },
    { name: 'Szwecja', legacyName: 'Sweden', rating: 4, icon: 'se' },
    { name: 'Ukraina', legacyName: 'Ukraine', rating: 4, icon: 'ua' },
    { name: 'Stany Zjednoczone', legacyName: 'United States', rating: 4, icon: 'us' },
    { name: 'Walia', legacyName: 'Wales', rating: 3.5, icon: 'gb-wls' }
];

const HOME_STATE_STORAGE_KEY = 'tournament-home-state-v1';
const GROUP_STORAGE_PREFIX = 'tournament-group-';
const MATCH_STORAGE_PREFIX = 'tournament-match-';
const KNOCKOUT_STORAGE_KEY = 'tournament-knockout-state-v1';

const createDefaultPlayers = () => ([
    { name: 'Mieszko', teams: [], goalsScored: 0 },
    { name: 'Wiktor', teams: [], goalsScored: 0 },
    { name: 'Maciek', teams: [], goalsScored: 0 }
]);

const createDefaultLastTeam = () => ({ name: 'Ostatnia druzyna', teams: [], goalsScored: 0 });

export default {
    name: 'HomePage',
    components: {
        Player,
        Group,
        Knockout,
        Results
    },
    data() {
        return {
            players: createDefaultPlayers(),
            lastTeam: createDefaultLastTeam(),
            goalsBySource: {},
            revealActive: false,
            revealItem: null,
            revealTypedName: '',
            revealShowFlag: false,
            revealTypingInProgress: false,
            revealTypingIntervalId: null,
            revealEndTimeoutId: null,
            revealResolver: null
        }
    },
    computed: {
        allTeams() {
            return this.players.reduce((acc, player) => {
                acc.push(...player.teams);
                return acc;
            }, [...this.lastTeam.teams]);
        },
        totalGoals() {
            return Object.values(this.goalsBySource).reduce((acc, value) => acc + value.goals, 0);
        },
        revealCurrentOwner() {
            return this.revealItem ? `Wlasciciel: ${this.revealItem.owner}` : '';
        },
        isTypingName() {
            return this.revealTypingInProgress;
        }
    },
    methods: {
        isStorageAvailable() {
            return typeof window !== 'undefined' && !!window.localStorage;
        },
        sanitizeTeam(team) {
            if (!team || !team.name) {
                return null;
            }

            return TEAMS.find((knownTeam) => knownTeam.name === team.name || knownTeam.legacyName === team.name) || null;
        },
        sanitizePlayer(player, fallbackName) {
            const base = {
                name: fallbackName,
                teams: [],
                goalsScored: 0
            };

            if (!player || typeof player !== 'object') {
                return base;
            }

            return {
                name: player.name || fallbackName,
                teams: Array.isArray(player.teams)
                    ? player.teams
                        .map((team) => this.sanitizeTeam(team))
                        .filter(Boolean)
                    : [],
                goalsScored: this.normalizeGoals(player.goalsScored)
            };
        },
        recalculateGoalsScored() {
            const sumForTeamNames = (teamNames) => {
                const namesSet = new Set(teamNames);
                return Object.values(this.goalsBySource).reduce((acc, entry) => {
                    return namesSet.has(entry.team) ? acc + entry.goals : acc;
                }, 0);
            };

            this.players.forEach((player) => {
                player.goalsScored = sumForTeamNames(player.teams.map((teamInfo) => teamInfo.name));
            });

            this.lastTeam.goalsScored = sumForTeamNames(this.lastTeam.teams.map((teamInfo) => teamInfo.name));
        },
        saveHomeState() {
            if (!this.isStorageAvailable()) {
                return;
            }

            try {
                window.localStorage.setItem(
                    HOME_STATE_STORAGE_KEY,
                    JSON.stringify({
                        players: this.players,
                        lastTeam: this.lastTeam,
                        goalsBySource: this.goalsBySource
                    })
                );
            } catch (error) {
                void error;
            }
        },
        loadHomeState() {
            if (!this.isStorageAvailable()) {
                return;
            }

            try {
                const rawState = window.localStorage.getItem(HOME_STATE_STORAGE_KEY);

                if (!rawState) {
                    return;
                }

                const parsedState = JSON.parse(rawState);
                const loadedPlayers = Array.isArray(parsedState.players) ? parsedState.players : [];

                this.players = createDefaultPlayers().map((defaultPlayer, index) => {
                    return this.sanitizePlayer(loadedPlayers[index], defaultPlayer.name);
                });

                this.lastTeam = this.sanitizePlayer(parsedState.lastTeam, 'Ostatnia druzyna');

                this.goalsBySource = Object.entries(parsedState.goalsBySource || {}).reduce((acc, [key, entry]) => {
                    if (!entry || !entry.team) {
                        return acc;
                    }

                    acc[key] = {
                        team: entry.team,
                        goals: this.normalizeGoals(entry.goals)
                    };

                    return acc;
                }, {});

                this.recalculateGoalsScored();
            } catch (error) {
                void error;
            }
        },
        resetChildStorage() {
            if (!this.isStorageAvailable()) {
                return;
            }

            const keysToRemove = Object.keys(window.localStorage).filter((key) => {
                return key.startsWith(GROUP_STORAGE_PREFIX) || key.startsWith(MATCH_STORAGE_PREFIX) || key === KNOCKOUT_STORAGE_KEY;
            });

            keysToRemove.forEach((key) => {
                window.localStorage.removeItem(key);
            });
        },
        normalizeGoals(goals) {
            const parsed = Number.parseInt(goals, 10);
            return Number.isFinite(parsed) && parsed > 0 ? parsed : 0;
        },
        setBodyScrollLock(shouldLock) {
            if (typeof document === 'undefined') {
                return;
            }

            document.body.style.overflow = shouldLock ? 'hidden' : '';
        },
        clearRevealTimers() {
            if (this.revealTypingIntervalId) {
                window.clearTimeout(this.revealTypingIntervalId);
                this.revealTypingIntervalId = null;
            }

            if (this.revealEndTimeoutId) {
                window.clearTimeout(this.revealEndTimeoutId);
                this.revealEndTimeoutId = null;
            }
        },
        finishRevealAnimation() {
            this.clearRevealTimers();
            this.revealActive = false;
            this.setBodyScrollLock(false);

            const resolve = this.revealResolver;
            this.revealResolver = null;

            if (typeof resolve === 'function') {
                resolve();
            }
        },
        showTeamRevealAnimation(payload) {
            if (!payload || !payload.team) {
                return Promise.resolve();
            }

            if (this.revealActive) {
                this.finishRevealAnimation();
            }

            this.clearRevealTimers();
            this.revealItem = {
                owner: payload.owner || 'Gracz',
                team: payload.team
            };
            this.revealTypedName = '';
            this.revealShowFlag = false;
            this.revealTypingInProgress = true;
            this.revealActive = true;
            this.setBodyScrollLock(true);

            const fullName = this.revealItem.team.name;
            const displayChars = fullName.split('').map((char) => {
                return char === ' ' ? ' ' : '·';
            });

            const pendingIndexes = fullName
                .split('')
                .map((char, index) => {
                    return char === ' ' ? -1 : index;
                })
                .filter((index) => index >= 0);

            this.revealTypedName = displayChars.join('');

            return new Promise((resolve) => {
                this.revealResolver = resolve;

                let revealedCount = 0;

                const revealNextLetter = () => {
                    if (!pendingIndexes.length) {
                        this.clearRevealTimers();
                        this.revealTypingInProgress = false;
                        this.revealTypedName = fullName;
                        this.revealShowFlag = true;
                        this.revealEndTimeoutId = window.setTimeout(() => {
                            this.finishRevealAnimation();
                        }, 900);
                        return;
                    }

                    const randomIndex = Math.floor(Math.random() * pendingIndexes.length);
                    const targetPosition = pendingIndexes.splice(randomIndex, 1)[0];
                    displayChars[targetPosition] = fullName[targetPosition];
                    this.revealTypedName = displayChars.join('');
                    revealedCount += 1;

                    const nextDelay = revealedCount < 4 ? 800 : 400;
                    this.revealTypingIntervalId = window.setTimeout(revealNextLetter, nextDelay);
                };

                this.revealTypingIntervalId = window.setTimeout(revealNextLetter, 800);
            });
        },
        skipRevealAnimation() {
            if (this.revealItem) {
                this.revealTypedName = this.revealItem.team.name;
                this.revealShowFlag = true;
            }

            this.revealTypingInProgress = false;

            this.finishRevealAnimation();
        },
        resetRevealState() {
            this.clearRevealTimers();
            this.revealActive = false;
            this.revealItem = null;
            this.revealTypedName = '';
            this.revealShowFlag = false;
            this.revealTypingInProgress = false;
            this.revealResolver = null;
            this.setBodyScrollLock(false);
        },
        resetAllGoals() {
            this.goalsBySource = {};
            this.players.forEach((player) => {
                player.goalsScored = 0;
            });
            this.lastTeam.goalsScored = 0;
        },
        roll() {
            this.resetChildStorage();
            this.resetRevealState();
            this.players.forEach((player) => {
                player.teams = [];
            });
            this.lastTeam.teams = [];
            this.resetAllGoals();
            const teamsToRollCopy = [...TEAMS];
            this.players.forEach((player) => {
                for (let i = 0; i < 5; i++) {
                    const randomIndex = Math.floor(Math.random() * teamsToRollCopy.length);
                    player.teams.push(teamsToRollCopy[randomIndex]);
                    teamsToRollCopy.splice(randomIndex, 1);
                }
            });
            const randomIndex = Math.floor(Math.random() * teamsToRollCopy.length);
            this.lastTeam.teams.push(teamsToRollCopy[randomIndex]);
            teamsToRollCopy.splice(randomIndex, 1);
        },
        setGoalsScored(goals, team, sourceKey) {
            if (!team) {
                return;
            }

            const key = sourceKey || `team:${team}`;

            this.goalsBySource = {
                ...this.goalsBySource,
                [key]: {
                    team,
                    goals: this.normalizeGoals(goals)
                }
            };

            this.recalculateGoalsScored();
        }
    },
    mounted() {
        this.loadHomeState();
    },
    beforeUnmount() {
        this.clearRevealTimers();
        this.setBodyScrollLock(false);
    },
    watch: {
        players: {
            handler() {
                this.saveHomeState();
            },
            deep: true
        },
        lastTeam: {
            handler() {
                this.saveHomeState();
            },
            deep: true
        },
        goalsBySource: {
            handler() {
                this.saveHomeState();
            },
            deep: true
        }
    }
}
</script>
<style scoped>
.home-wrapper {
    max-width: 1400px;
    margin: 0 auto;
    padding: 48px 18px 90px;
}

.hero {
    padding: 36px;
    border-radius: 28px;
    background: linear-gradient(130deg, #1f6f4e, #3b8d6e 45%, #f1cf8b);
    color: #ffffff;
    box-shadow: 0 16px 50px rgba(31, 84, 53, 0.3);
}

.hero h1 {
    margin: 0;
    font-family: 'Bebas Neue', cursive;
    font-size: clamp(2.4rem, 5vw, 4rem);
    letter-spacing: 0.06em;
}

.hero p {
    margin: 10px 0 0;
    max-width: 620px;
    font-size: 1.06rem;
}

.hero-actions {
    margin-top: 24px;
    display: flex;
    align-items: center;
    gap: 14px;
    flex-wrap: wrap;
}

.stats-chip {
    background: rgba(255, 255, 255, 0.2);
    padding: 10px 16px;
    border-radius: 999px;
    font-weight: 700;
}

section {
    margin-top: 38px;
}

h2 {
    font-family: 'Bebas Neue', cursive;
    font-size: 2rem;
    letter-spacing: 0.04em;
    margin-bottom: 16px;
}

.players-grid,
.group-grid {
    display: grid;
    gap: 16px;
}

.players-grid {
    grid-template-columns: repeat(auto-fit, minmax(270px, 1fr));
}

.group-grid {
    grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
}

.reveal-overlay {
    position: fixed;
    inset: 0;
    z-index: 1200;
    background:
        radial-gradient(circle at 18% 20%, rgba(90, 237, 186, 0.18), transparent 40%),
        radial-gradient(circle at 83% 24%, rgba(241, 207, 139, 0.22), transparent 44%),
        linear-gradient(145deg, #07281d 4%, #103d2f 52%, #1a5d49 100%);
    display: grid;
    place-items: center;
    overflow: hidden;
}

.reveal-glow {
    position: absolute;
    width: 42vw;
    height: 42vw;
    min-width: 320px;
    min-height: 320px;
    border-radius: 50%;
    filter: blur(20px);
    opacity: 0.42;
    animation: pulse-glow 3.6s ease-in-out infinite;
}

.reveal-glow-left {
    left: -10vw;
    top: -8vw;
    background: #72e2b8;
}

.reveal-glow-right {
    right: -8vw;
    bottom: -10vw;
    background: #ffc87a;
    animation-delay: 0.8s;
}

.reveal-content {
    position: relative;
    width: min(900px, calc(100vw - 30px));
    padding: clamp(20px, 4vw, 44px);
    border-radius: 30px;
    border: 1px solid rgba(255, 255, 255, 0.2);
    background: rgba(7, 23, 17, 0.62);
    backdrop-filter: blur(8px);
    box-shadow: 0 28px 65px rgba(0, 0, 0, 0.45);
    color: #f3f6ef;
}

.reveal-header {
    text-align: center;
}

.reveal-kicker {
    display: inline-block;
    letter-spacing: 0.1em;
    text-transform: uppercase;
    font-size: 0.78rem;
    opacity: 0.82;
}

.reveal-header h2 {
    margin: 8px 0 6px;
    font-size: clamp(2.2rem, 4.7vw, 3.5rem);
    letter-spacing: 0.06em;
    color: #f9f8f1;
}

.reveal-header p {
    margin: 0;
    font-weight: 600;
    color: rgba(245, 248, 239, 0.86);
}

.reveal-card {
    margin: 24px auto 0;
    max-width: 560px;
    border-radius: 24px;
    padding: clamp(16px, 2.4vw, 24px);
    border: 1px solid rgba(255, 255, 255, 0.14);
    background: linear-gradient(130deg, rgba(255, 255, 255, 0.1), rgba(255, 255, 255, 0.03));
    text-align: center;
}

.owner-chip {
    display: inline-block;
    padding: 6px 12px;
    border-radius: 999px;
    background: rgba(114, 226, 184, 0.2);
    color: #d9ffef;
    font-weight: 700;
}

.team-line {
    margin-top: 62px;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 12px;
}

.team-line h3 {
    margin: 0;
    font-size: clamp(1.7rem, 3.8vw, 2.9rem);
    font-family: 'Bebas Neue', cursive;
    letter-spacing: 0.05em;
    min-height: 1.25em;
}

.typing-caret {
    display: inline-block;
    margin-left: 2px;
    animation: caret-blink 0.8s step-end infinite;
}

.reveal-flag {
    transform-origin: center;
}

.team-rating {
    margin-top: 6px;
    display: flex;
    justify-content: center;
}

.reveal-actions {
    margin-top: 20px;
    display: flex;
    justify-content: center;
}

.reveal-fade-enter-active,
.reveal-fade-leave-active {
    transition: opacity 0.3s ease;
}

.reveal-fade-enter-from,
.reveal-fade-leave-to {
    opacity: 0;
}

.card-pop-enter-active {
    animation: card-pop 0.52s ease;
}

.card-pop-leave-active {
    transition: opacity 0.15s ease;
}

.card-pop-leave-to {
    opacity: 0;
}

.flag-pop-enter-active {
    animation: flag-pop 0.32s ease;
}

.flag-pop-leave-active {
    transition: opacity 0.15s ease;
}

.flag-pop-leave-to {
    opacity: 0;
}

@keyframes pulse-glow {
    0%,
    100% {
        transform: scale(1) translateY(0);
    }

    50% {
        transform: scale(1.15) translateY(-8px);
    }
}

@keyframes card-pop {
    0% {
        transform: translateY(18px) scale(0.95);
        opacity: 0;
    }

    70% {
        transform: translateY(0) scale(1.02);
        opacity: 1;
    }

    100% {
        transform: translateY(0) scale(1);
        opacity: 1;
    }
}

@keyframes caret-blink {
    0%,
    50% {
        opacity: 1;
    }

    51%,
    100% {
        opacity: 0;
    }
}

@keyframes flag-pop {
    0% {
        opacity: 0;
        transform: scale(0.75) rotate(-8deg);
    }

    100% {
        opacity: 1;
        transform: scale(1) rotate(0deg);
    }
}

@media (max-width: 700px) {
    .hero {
        padding: 28px 20px;
    }

    .reveal-content {
        border-radius: 24px;
        padding: 18px 16px 20px;
    }

    .reveal-card {
        margin-top: 18px;
    }

    .team-line {
        margin-top: 44px;
    }
}
</style>
