<template>
    <v-card class="group-card" rounded="xl" elevation="6">
        <v-card-title class="group-title">Grupa {{ groupName }}</v-card-title>
        <v-card-text>
            <div class="selection-grid">
                <v-select
                    v-for="slot in 4"
                    :key="slot"
                    :label="`Druzyna ${slot}`"
                    :items="availableTeams(slot - 1)"
                    item-title="name"
                    variant="outlined"
                    return-object
                    hide-details
                    density="comfortable"
                    :model-value="groupTeams[slot - 1]"
                    @update:modelValue="(value) => changeTeam(value, slot - 1)"
                >
                    <template #selection="{ item }">
                        <div class="team-choice">
                            <flag :iso="item.raw.icon" />
                            {{ item.raw.name }}
                        </div>
                    </template>
                    <template #item="{ item, props }">
                        <v-list-item v-bind="props" title="">
                            <div class="team-choice">
                                <flag :iso="item.raw.icon" />
                                {{ item.raw.name }}
                            </div>
                        </v-list-item>
                    </template>
                </v-select>
            </div>

            <div v-if="isReady" class="matches-wrap">
                <Match
                    v-for="(match, index) in groupMatches"
                    :key="`${match.team1.name}-${match.team2.name}`"
                    :team1="match.team1"
                    :team2="match.team2"
                    :addGoalsScored="addGoalsScored"
                    :matchId="`group-${groupName}-${index}`"
                />
            </div>
            <div v-else class="placeholder">Wybierz 4 rozne druzyny, aby rozpisac mecze grupowe.</div>
        </v-card-text>
    </v-card>
</template>
<script>
import Match from '@/components/Match.vue';

export default {
    name: 'Group',
    components: {
        Match,
    },
    data() {
        return {
            groupTeams: [null, null, null, null]
        }
    },
    props: {
        teams: {
            type: Array,
            required: true
        },
        groupName: {
            type: String
        },
        addGoalsScored: {
            type: Function,
            required: true
        }
    },
    methods: {
        isStorageAvailable() {
            return typeof window !== 'undefined' && !!window.localStorage;
        },
        storageKey() {
            return `tournament-group-${this.groupName}-teams-v1`;
        },
        saveGroupTeams() {
            if (!this.isStorageAvailable()) {
                return;
            }

            try {
                const names = this.groupTeams.map((team) => team?.name || null);
                window.localStorage.setItem(this.storageKey(), JSON.stringify(names));
            } catch (error) {
                void error;
            }
        },
        loadGroupTeams() {
            if (!this.isStorageAvailable()) {
                return;
            }

            try {
                const raw = window.localStorage.getItem(this.storageKey());

                if (!raw) {
                    return;
                }

                const teamNames = JSON.parse(raw);

                if (!Array.isArray(teamNames)) {
                    return;
                }

                this.groupTeams = teamNames.slice(0, 4).map((teamName) => {
                    if (!teamName) {
                        return null;
                    }

                    return this.teams.find((team) => team.name === teamName) || null;
                });

                while (this.groupTeams.length < 4) {
                    this.groupTeams.push(null);
                }
            } catch (error) {
                void error;
            }
        },
        syncGroupTeamsWithAvailableTeams() {
            this.groupTeams = this.groupTeams.map((selectedTeam) => {
                if (!selectedTeam) {
                    return null;
                }

                return this.teams.find((team) => team.name === selectedTeam.name) || null;
            });
        },
        changeTeam(team, index) {
            this.groupTeams[index] = team;
        },
        availableTeams(slotIndex) {
            const alreadyUsed = this.groupTeams
                .filter((team, index) => index !== slotIndex)
                .map((team) => team?.name)
                .filter(Boolean);

            return this.teams.filter((team) => {
                return !alreadyUsed.includes(team.name) || this.groupTeams[slotIndex]?.name === team.name;
            });
        }
    },
    computed: {
        isReady() {
            return this.groupTeams.every(Boolean);
        },
        groupMatches() {
            if (!this.isReady) {
                return [];
            }

            const [team1, team2, team3, team4] = this.groupTeams;
            return [
                { team1, team2 },
                { team1, team2: team3 },
                { team1, team2: team4 },
                { team1: team2, team2: team3 },
                { team1: team2, team2: team4 },
                { team1: team3, team2: team4 }
            ];
        }
    },
    mounted() {
        this.loadGroupTeams();
    },
    watch: {
        groupTeams: {
            handler() {
                this.saveGroupTeams();
            },
            deep: true
        },
        teams: {
            handler() {
                this.syncGroupTeamsWithAvailableTeams();
            },
            deep: true
        }
    }
}
</script>
<style scoped>
.group-card {
    height: 100%;
}

.group-title {
    font-family: 'Bebas Neue', cursive;
    letter-spacing: 0.05em;
    font-size: 1.7rem;
}

.selection-grid {
    display: grid;
    gap: 10px;
    grid-template-columns: repeat(2, minmax(0, 1fr));
}

.team-choice {
    display: flex;
    align-items: center;
    gap: 10px;
}

.matches-wrap {
    margin-top: 14px;
    display: grid;
    gap: 8px;
}

.placeholder {
    margin-top: 14px;
    font-size: 0.9rem;
    opacity: 0.7;
}

@media (max-width: 560px) {
    .selection-grid {
        grid-template-columns: 1fr;
    }
}
</style>