<template>
    <v-card rounded="xl" elevation="6" class="knockout-card">
        <v-card-title class="title">Drabinka pucharowa</v-card-title>
        <v-card-text>
            <div class="round-grid">
                <div class="round-card">
                    <h3>Cwiercfinaly</h3>
                    <div v-for="(match, index) in quarterfinals" :key="`qf-${index}`">
                        <div class="match-box">
                            <div class="pair-row">
                                <div class="side-block">
                                    <v-select
                                        :label="`Cwiercfinal ${index + 1} - druzyna 1`"
                                        :items="availableQuarterfinalTeams(index, 'team1')"
                                        item-title="name"
                                        return-object
                                        variant="outlined"
                                        hide-details
                                        density="comfortable"
                                        :model-value="match.team1"
                                        @update:modelValue="(value) => onQuarterTeamChange(index, 'team1', value)"
                                    >
                                        <template #selection="{ item }">
                                            <div class="team-choice">
                                                <flag :iso="item.raw.icon" />
                                                {{ item.raw.name }}
                                            </div>
                                        </template>
                                        <template #item="{ item, props }">
                                            <v-list-item v-bind="props" title="">
                                                <div class="team-choice">
                                                    <flag :iso="item.raw.icon" />
                                                    {{ item.raw.name }}
                                                </div>
                                            </v-list-item>
                                        </template>
                                    </v-select>
                                    <v-text-field
                                        label="Gole"
                                        type="number"
                                        min="0"
                                        variant="outlined"
                                        hide-details
                                        density="comfortable"
                                        :model-value="match.goals1"
                                        class="goals-input"
                                        @update:modelValue="(value) => onQuarterGoalsChange(index, 'goals1', value)"
                                    />
                                </div>
                                <div class="side-block">
                                    <v-select
                                        :label="`Cwiercfinal ${index + 1} - druzyna 2`"
                                        :items="availableQuarterfinalTeams(index, 'team2')"
                                        item-title="name"
                                        return-object
                                        variant="outlined"
                                        hide-details
                                        density="comfortable"
                                        :model-value="match.team2"
                                        @update:modelValue="(value) => onQuarterTeamChange(index, 'team2', value)"
                                    >
                                        <template #selection="{ item }">
                                            <div class="team-choice">
                                                <flag :iso="item.raw.icon" />
                                                {{ item.raw.name }}
                                            </div>
                                        </template>
                                        <template #item="{ item, props }">
                                            <v-list-item v-bind="props" title="">
                                                <div class="team-choice">
                                                    <flag :iso="item.raw.icon" />
                                                    {{ item.raw.name }}
                                                </div>
                                            </v-list-item>
                                        </template>
                                    </v-select>
                                    <v-text-field
                                        label="Gole"
                                        type="number"
                                        min="0"
                                        variant="outlined"
                                        hide-details
                                        density="comfortable"
                                        :model-value="match.goals2"
                                        class="goals-input"
                                        @update:modelValue="(value) => onQuarterGoalsChange(index, 'goals2', value)"
                                    />
                                </div>
                            </div>
                            <div v-if="isDraw(match.goals1, match.goals2) && match.team1 && match.team2" class="penalty-row">
                                <v-btn
                                    size="small"
                                    variant="tonal"
                                    color="primary"
                                    :class="{ 'penalty-active': match.penaltyWinner === 'team1' }"
                                    @click="onQuarterPenaltyChange(index, 'team1')"
                                >
                                    {{ match.team1.name }} wygral po karnych
                                </v-btn>
                                <v-btn
                                    size="small"
                                    variant="tonal"
                                    color="primary"
                                    :class="{ 'penalty-active': match.penaltyWinner === 'team2' }"
                                    @click="onQuarterPenaltyChange(index, 'team2')"
                                >
                                    {{ match.team2.name }} wygral po karnych
                                </v-btn>
                            </div>
                        </div>
                    </div>
                </div>

                <div class="round-card">
                    <h3>Polfinaly</h3>
                    <div v-for="(match, index) in semifinals" :key="`sf-${index}`">
                        <div class="match-box">
                            <div class="pair-row">
                                <div class="side-block">
                                    <div class="readonly-team">
                                        <flag v-if="quarterWinners[index * 2]?.icon" :iso="quarterWinners[index * 2].icon" />
                                        <span>{{ quarterWinners[index * 2]?.name || 'Zwyciezca cwiercfinalu' }}</span>
                                    </div>
                                    <v-text-field
                                        label="Gole"
                                        type="number"
                                        min="0"
                                        variant="outlined"
                                        hide-details
                                        density="comfortable"
                                        :model-value="match.goals1"
                                        class="goals-input"
                                        @update:modelValue="(value) => onSemifinalGoalsChange(index, 'goals1', value)"
                                    />
                                </div>
                                <div class="side-block">
                                    <div class="readonly-team">
                                        <flag v-if="quarterWinners[index * 2 + 1]?.icon" :iso="quarterWinners[index * 2 + 1].icon" />
                                        <span>{{ quarterWinners[index * 2 + 1]?.name || 'Zwyciezca cwiercfinalu' }}</span>
                                    </div>
                                    <v-text-field
                                        label="Gole"
                                        type="number"
                                        min="0"
                                        variant="outlined"
                                        hide-details
                                        density="comfortable"
                                        :model-value="match.goals2"
                                        class="goals-input"
                                        @update:modelValue="(value) => onSemifinalGoalsChange(index, 'goals2', value)"
                                    />
                                </div>
                            </div>
                            <div
                                v-if="isDraw(match.goals1, match.goals2) && quarterWinners[index * 2] && quarterWinners[index * 2 + 1]"
                                class="penalty-row"
                            >
                                <v-btn
                                    size="small"
                                    variant="tonal"
                                    color="primary"
                                    :class="{ 'penalty-active': match.penaltyWinner === 'team1' }"
                                    @click="onSemifinalPenaltyChange(index, 'team1')"
                                >
                                    {{ quarterWinners[index * 2].name }} wygral po karnych
                                </v-btn>
                                <v-btn
                                    size="small"
                                    variant="tonal"
                                    color="primary"
                                    :class="{ 'penalty-active': match.penaltyWinner === 'team2' }"
                                    @click="onSemifinalPenaltyChange(index, 'team2')"
                                >
                                    {{ quarterWinners[index * 2 + 1].name }} wygral po karnych
                                </v-btn>
                            </div>
                        </div>
                    </div>
                </div>

                <div class="round-card final-card">
                    <h3>Final</h3>
                    <div class="pair-row">
                        <div class="side-block">
                            <div class="readonly-team">
                                <flag v-if="semifinalWinners[0]?.icon" :iso="semifinalWinners[0].icon" />
                                <span>{{ semifinalWinners[0]?.name || 'Zwyciezca polfinalu' }}</span>
                            </div>
                            <v-text-field
                                label="Gole"
                                type="number"
                                min="0"
                                variant="outlined"
                                hide-details
                                density="comfortable"
                                :model-value="final.goals1"
                                class="goals-input"
                                @update:modelValue="(value) => onFinalGoalsChange('goals1', value)"
                            />
                        </div>
                        <div class="side-block">
                            <div class="readonly-team">
                                <flag v-if="semifinalWinners[1]?.icon" :iso="semifinalWinners[1].icon" />
                                <span>{{ semifinalWinners[1]?.name || 'Zwyciezca polfinalu' }}</span>
                            </div>
                            <v-text-field
                                label="Gole"
                                type="number"
                                min="0"
                                variant="outlined"
                                hide-details
                                density="comfortable"
                                :model-value="final.goals2"
                                class="goals-input"
                                @update:modelValue="(value) => onFinalGoalsChange('goals2', value)"
                            />
                        </div>
                    </div>
                    <div class="winner-chip">
                        Zwyciezca: {{ champion?.name || 'brak (remis lub brak danych)' }}
                    </div>
                </div>
            </div>
        </v-card-text>
    </v-card>
</template>

<script>
const KNOCKOUT_STORAGE_KEY = 'tournament-knockout-state-v1';

const createQuarterfinals = () => {
    return Array.from({ length: 4 }, () => ({ team1: null, team2: null, goals1: 0, goals2: 0, penaltyWinner: null }));
};

const createSemifinals = () => {
    return Array.from({ length: 2 }, () => ({ goals1: 0, goals2: 0, penaltyWinner: null }));
};

export default {
    name: 'Knockout',
    props: {
        teams: {
            type: Array,
            required: true
        },
        addGoalsScored: {
            type: Function,
            required: true
        }
    },
    data() {
        return {
            quarterfinals: createQuarterfinals(),
            semifinals: createSemifinals(),
            final: { goals1: 0, goals2: 0 },
            emittedByKey: {}
        };
    },
    computed: {
        quarterWinners() {
            return this.quarterfinals.map((match) => {
                return this.resolveWinner(match.team1, match.team2, match.goals1, match.goals2, match.penaltyWinner);
            });
        },
        semifinalWinners() {
            return this.semifinals.map((match, index) => {
                const team1 = this.quarterWinners[index * 2];
                const team2 = this.quarterWinners[index * 2 + 1];
                return this.resolveWinner(team1, team2, match.goals1, match.goals2, match.penaltyWinner);
            });
        },
        champion() {
            return this.resolveWinner(
                this.semifinalWinners[0],
                this.semifinalWinners[1],
                this.final.goals1,
                this.final.goals2
            );
        }
    },
    methods: {
        isStorageAvailable() {
            return typeof window !== 'undefined' && !!window.localStorage;
        },
        findTeamByName(teamName) {
            if (!teamName) {
                return null;
            }

            return this.teams.find((team) => team.name === teamName) || null;
        },
        sanitizePenaltyWinner(value) {
            return value === 'team1' || value === 'team2' ? value : null;
        },
        saveKnockoutState() {
            if (!this.isStorageAvailable()) {
                return;
            }

            try {
                const serialized = {
                    quarterfinals: this.quarterfinals.map((match) => ({
                        team1: match.team1?.name || null,
                        team2: match.team2?.name || null,
                        goals1: this.normalizeGoals(match.goals1),
                        goals2: this.normalizeGoals(match.goals2),
                        penaltyWinner: this.sanitizePenaltyWinner(match.penaltyWinner)
                    })),
                    semifinals: this.semifinals.map((match) => ({
                        goals1: this.normalizeGoals(match.goals1),
                        goals2: this.normalizeGoals(match.goals2),
                        penaltyWinner: this.sanitizePenaltyWinner(match.penaltyWinner)
                    })),
                    final: {
                        goals1: this.normalizeGoals(this.final.goals1),
                        goals2: this.normalizeGoals(this.final.goals2)
                    }
                };

                window.localStorage.setItem(KNOCKOUT_STORAGE_KEY, JSON.stringify(serialized));
            } catch (error) {
                void error;
            }
        },
        loadKnockoutState() {
            if (!this.isStorageAvailable()) {
                return;
            }

            try {
                const raw = window.localStorage.getItem(KNOCKOUT_STORAGE_KEY);

                if (!raw) {
                    return;
                }

                const parsed = JSON.parse(raw);
                const loadedQuarterfinals = Array.isArray(parsed.quarterfinals) ? parsed.quarterfinals : [];
                const loadedSemifinals = Array.isArray(parsed.semifinals) ? parsed.semifinals : [];

                this.quarterfinals = createQuarterfinals().map((match, index) => {
                    const loadedMatch = loadedQuarterfinals[index] || {};
                    return {
                        team1: this.findTeamByName(loadedMatch.team1),
                        team2: this.findTeamByName(loadedMatch.team2),
                        goals1: this.normalizeGoals(loadedMatch.goals1),
                        goals2: this.normalizeGoals(loadedMatch.goals2),
                        penaltyWinner: this.sanitizePenaltyWinner(loadedMatch.penaltyWinner)
                    };
                });

                this.semifinals = createSemifinals().map((match, index) => {
                    const loadedMatch = loadedSemifinals[index] || {};
                    return {
                        goals1: this.normalizeGoals(loadedMatch.goals1),
                        goals2: this.normalizeGoals(loadedMatch.goals2),
                        penaltyWinner: this.sanitizePenaltyWinner(loadedMatch.penaltyWinner)
                    };
                });

                this.final = {
                    goals1: this.normalizeGoals(parsed.final?.goals1),
                    goals2: this.normalizeGoals(parsed.final?.goals2)
                };
            } catch (error) {
                void error;
            }
        },
        resetKnockoutState() {
            this.quarterfinals = createQuarterfinals();
            this.semifinals = createSemifinals();
            this.final = { goals1: 0, goals2: 0 };
            this.emittedByKey = {};
        },
        syncAllGoals() {
            this.quarterfinals.forEach((_, index) => {
                this.syncMatchGoals('qf', index);
            });

            this.semifinals.forEach((_, index) => {
                this.syncMatchGoals('sf', index);
            });

            this.syncMatchGoals('f', 0);
        },
        normalizeGoals(value) {
            const parsed = Number.parseInt(value, 10);
            return Number.isFinite(parsed) && parsed > 0 ? parsed : 0;
        },
        resolveWinner(team1, team2, goals1, goals2, penaltyWinner) {
            if (!team1 || !team2) {
                return null;
            }

            if (goals1 === goals2) {
                if (penaltyWinner === 'team1') {
                    return team1;
                }

                if (penaltyWinner === 'team2') {
                    return team2;
                }

                return null;
            }

            return goals1 > goals2 ? team1 : team2;
        },
        isDraw(goals1, goals2) {
            return goals1 === goals2;
        },
        availableQuarterfinalTeams(matchIndex, side) {
            const selectedByOthers = this.quarterfinals
                .flatMap((match, index) => {
                    if (index === matchIndex) {
                        return side === 'team1' ? [match.team2?.name] : [match.team1?.name];
                    }

                    return [match.team1?.name, match.team2?.name];
                })
                .filter(Boolean);

            const currentMatch = this.quarterfinals[matchIndex];
            const currentTeam = side === 'team1' ? currentMatch.team1 : currentMatch.team2;

            return this.teams.filter((team) => {
                return !selectedByOthers.includes(team.name) || currentTeam?.name === team.name;
            });
        },
        onQuarterTeamChange(index, side, team) {
            this.quarterfinals[index][side] = team;
            this.syncMatchGoals('qf', index);
            this.syncMatchGoals('sf', Math.floor(index / 2));
            this.syncMatchGoals('f', 0);
        },
        onQuarterGoalsChange(index, side, value) {
            this.quarterfinals[index][side] = this.normalizeGoals(value);
            if (!this.isDraw(this.quarterfinals[index].goals1, this.quarterfinals[index].goals2)) {
                this.quarterfinals[index].penaltyWinner = null;
            }
            this.syncMatchGoals('qf', index);
            this.syncMatchGoals('sf', Math.floor(index / 2));
            this.syncMatchGoals('f', 0);
        },
        onQuarterPenaltyChange(index, winner) {
            this.quarterfinals[index].penaltyWinner = winner;
            this.syncMatchGoals('sf', Math.floor(index / 2));
            this.syncMatchGoals('f', 0);
        },
        onSemifinalGoalsChange(index, side, value) {
            this.semifinals[index][side] = this.normalizeGoals(value);
            if (!this.isDraw(this.semifinals[index].goals1, this.semifinals[index].goals2)) {
                this.semifinals[index].penaltyWinner = null;
            }
            this.syncMatchGoals('sf', index);
            this.syncMatchGoals('f', 0);
        },
        onSemifinalPenaltyChange(index, winner) {
            this.semifinals[index].penaltyWinner = winner;
            this.syncMatchGoals('f', 0);
        },
        onFinalGoalsChange(side, value) {
            this.final[side] = this.normalizeGoals(value);
            this.syncMatchGoals('f', 0);
        },
        setScoreForKey(sourceKey, team, goals) {
            if (!team) {
                const previousTeamName = this.emittedByKey[sourceKey];

                if (previousTeamName) {
                    this.addGoalsScored(0, previousTeamName, sourceKey);
                    delete this.emittedByKey[sourceKey];
                }

                return;
            }

            this.emittedByKey[sourceKey] = team.name;
            this.addGoalsScored(goals, team.name, sourceKey);
        },
        syncMatchGoals(round, index) {
            if (round === 'qf') {
                const match = this.quarterfinals[index];
                this.setScoreForKey(`cup-qf-${index}-team1`, match.team1, match.goals1);
                this.setScoreForKey(`cup-qf-${index}-team2`, match.team2, match.goals2);
                return;
            }

            if (round === 'sf') {
                const match = this.semifinals[index];
                const team1 = this.quarterWinners[index * 2];
                const team2 = this.quarterWinners[index * 2 + 1];
                this.setScoreForKey(`cup-sf-${index}-team1`, team1, match.goals1);
                this.setScoreForKey(`cup-sf-${index}-team2`, team2, match.goals2);
                return;
            }

            const team1 = this.semifinalWinners[0];
            const team2 = this.semifinalWinners[1];
            this.setScoreForKey('cup-f-team1', team1, this.final.goals1);
            this.setScoreForKey('cup-f-team2', team2, this.final.goals2);
        }
    },
    watch: {
        quarterfinals: {
            handler() {
                this.saveKnockoutState();
            },
            deep: true
        },
        semifinals: {
            handler() {
                this.saveKnockoutState();
            },
            deep: true
        },
        final: {
            handler() {
                this.saveKnockoutState();
            },
            deep: true
        },
        quarterWinners: {
            handler() {
                this.syncMatchGoals('sf', 0);
                this.syncMatchGoals('sf', 1);
                this.syncMatchGoals('f', 0);
            },
            deep: true
        },
        semifinalWinners: {
            handler() {
                this.syncMatchGoals('f', 0);
            },
            deep: true
        },
        teams: {
            handler(newTeams) {
                if (!newTeams.length) {
                    this.resetKnockoutState();
                    return;
                }

                const hasAnySavedTeams = this.quarterfinals.some((match) => match.team1 || match.team2);

                if (!hasAnySavedTeams) {
                    this.loadKnockoutState();
                }

                this.quarterfinals = this.quarterfinals.map((match) => ({
                    ...match,
                    team1: this.findTeamByName(match.team1?.name),
                    team2: this.findTeamByName(match.team2?.name)
                }));

                this.syncAllGoals();
            },
            deep: true,
            immediate: true
        }
    },
    mounted() {
        this.loadKnockoutState();
        this.syncAllGoals();
    }
};
</script>

<style scoped>
.knockout-card {
    overflow: hidden;
}

.title {
    font-family: 'Bebas Neue', cursive;
    letter-spacing: 0.05em;
    font-size: 1.7rem;
}

.round-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
    gap: 12px;
}

.round-card {
    background: rgba(0, 0, 0, 0.03);
    border-radius: 14px;
    padding: 12px;
    border: 1px solid rgba(0, 0, 0, 0.05);
}

.round-card h3 {
    margin: 0 0 10px;
    font-size: 1rem;
    letter-spacing: 0.03em;
}

.pair-row {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 8px;
    margin-bottom: 8px;
}

.match-box {
    margin-bottom: 10px;
    padding: 10px;
    border: 1px dashed rgba(0, 0, 0, 0.12);
    border-radius: 10px;
    background: rgba(255, 255, 255, 0.45);
}

.side-block {
    display: grid;
    grid-template-columns: minmax(0, 1fr) 88px;
    gap: 8px;
}

.readonly-team {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 0 10px;
    border-radius: 10px;
    background: rgba(0, 0, 0, 0.04);
    min-height: 40px;
}

.team-choice {
    display: flex;
    align-items: center;
    gap: 10px;
}

.goals-input {
    max-width: 88px;
}

.penalty-row {
    margin: 2px 0 0;
    display: flex;
    gap: 8px;
    flex-wrap: wrap;
}

.penalty-active {
    box-shadow: inset 0 0 0 2px rgba(31, 111, 78, 0.5);
}

.winner-chip {
    margin-top: 12px;
    padding: 10px;
    border-radius: 10px;
    background: rgba(31, 111, 78, 0.15);
    font-weight: 700;
}

@media (max-width: 900px) {
    .pair-row {
        grid-template-columns: 1fr;
    }

    .side-block {
        grid-template-columns: minmax(0, 1fr) 88px;
    }
}
</style>
